1	import { describe, it, expect } from "vitest";
2	import { scalePixelArt } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(scalePixelArt([], 2)).toEqual([]);
7	  });
8	  it("should return identical copy for scale 1 with single row", () => {
9	    expect(scalePixelArt([["R", "G", "B"]], 1)).toEqual([["R", "G", "B"]]);
10	  });
11	  it("should return identical copy for scale 1 with multiple rows", () => {
12	    expect(scalePixelArt([["R", "G"], ["B", "W"]], 1)).toEqual([["R", "G"], ["B", "W"]]);
